#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,M=1e6+10;int head[N],des[M],nxt[M],cgt=1,cap[M],dep[N],que[N],H,T,s,t,n,m;bool vis[N],jud[N];
inline void ins(const int &x,const int &y,const int &c)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
}
inline bool bfs()
{
	memset(dep,0,(t+2)<<2);dep[que[H=T=0]=s]=1;
	while(H<=T){int u=que[H++];grep(u,i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;} return dep[t];
}
inline int dfs(const int &u=s,int in=0x3f3f3f3f)
{
	if(u==t)return in;int out=0;grep(u,i)
	{
		int v=des[i];if(cap[i]&&dep[v]==dep[u]+1)
		{
			int tmp=dfs(v,cap[i]<in?cap[i]:in);
			cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
		}
	}
	return out?out:dep[u]=0;
}
inline void Dfs(const int &u){if(jud[u])return;jud[u]=true;grep(u,i)Dfs(des[i]);}
int main()
{
//	FIN("qwq.in");
	n=read();m=read();s=0;t=n+m+1;int sm=0;rep(1,n,i)
	{
		int x=read();sm+=x;ins(i,t,x);while(true)
		{
			int res=0;char ch=getchar();bool flag=0;
			while(ch<'0'||ch>'9'){if(ch=='\n'||ch=='\r'){flag=1;break;}ch=getchar();} if(flag) break;
			while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();ins(res+n,i,0x3f3f3f3f);
			if(ch=='\n'||ch=='\r')break;
		}
	}
	rep(1,m,i)ins(s,i+n,read());int ans=0;while(bfs())ans+=dfs(); 
	rep(1,n,i)if(!dep[i])printf("%d ",i);putchar('\n');
	rep(1,m,i)if(!dep[i+n])printf("%d ",i);putchar('\n');
	printf("%d\n",sm-ans); return 0;
}
